  id, 
  placeholder = "", 
  size = "md", 
  disabled = false, 
  error = false, 
  value = "", 
  onChange, 
  onFocus, 
  onBlur,
  type = "text",
  ...props 
}) => {
  // Mapping des tailles
  const sizeClasses = {
    sm: "px-[var(--spacing-sm)] py-[var(--spacing-xs)] text-[var(--font-size-sm)] min-h-[32px]",
    md: "px-[var(--spacing-sm)] py-[var(--spacing-sm)] text-[var(--font-size-md)] min-h-[40px]",
    lg: "px-[var(--spacing-md)] py-[var(--spacing-sm)] text-[var(--font-size-lg)] min-h-[48px]"
  };

