const Card = ({ 
  children, 
  padding = 'md', 
  className = '',
  role = 'region',
  ariaLabel = null
}) => {
  // Mapping des niveaux de padding vers les classes Tailwind
  const paddingClasses = {
    sm: 'p-[var(--component-card-padding-sm)]',
    md: 'p-[var(--component-card-padding-md)]',
    lg: 'p-[var(--component-card-padding-lg)]'
  };

  const paddingClass = paddingClasses[padding] || paddingClasses.md;

  return (
    <div
      role={role}
      aria-label={ariaLabel}
      className={`
        ${paddingClass}
        rounded-[var(--component-card-radius)]
        bg-[var(--component-card-bg)]
        border border-[var(--component-card-border)]
        shadow-[var(--component-card-shadow)]
        transition-shadow duration-200 ease-out
        focus-within:outline-none focus-within:ring-2 focus-within:ring-offset-2 focus-within:ring-blue-500
        ${className}
      `}
    >
      {children}
    </div>
  );
};

