    info: 'bg-blue-100 text-blue-800',
    primary: 'bg-blue-600 text-white'
  };

  const sizeStyles = {
    sm: 'px-2 py-1 text-xs',
    md: 'px-3 py-1.5 text-xs',
    lg: 'px-4 py-2 text-sm'
  };

  return (
    <span
